以下是一个使用C++编写的多进程TCP连接的服务端和客户端程序的示例：

**服务端程序（server.cpp）：**

```cpp
#include <iostream>
#include <sys/socket.h>
#include <netinet/in.h>
#include <unistd.h>

void handle_client(int client_socket) {
    // 处理客户端连接的逻辑
    struct sockaddr_in client_address;
    socklen_t addr_len = sizeof(client_address);
    getpeername(client_socket, (struct sockaddr*)&client_address, &addr_len);
    std::cout << "Handling client " << inet_ntoa(client_address.sin_addr) << ":" << ntohs(client_address.sin_port) << std::endl;

    // 接收客户端数据并发送响应
    char buffer[1024];
    ssize_t recv_bytes = recv(client_socket, buffer, sizeof(buffer), 0);
    if (recv_bytes > 0) {
        send(client_socket, "Server received: ", 16, 0);
        send(client_socket, buffer, recv_bytes, 0);
    }

    // 关闭客户端连接
    close(client_socket);
}

int main() {
    // 定义服务器 IP 和端口
    char* host = "127.0.0.1";
    int port = 12345;

    // 创建 TCP Socket
    int server_socket = socket(AF_INET, SOCK_STREAM, 0);
    if (server_socket == -1) {
        std::cerr << "Failed to create socket" << std::endl;
        return -1;
    }

    // 绑定 IP 和端口
    struct sockaddr_in server_address{};
    server_address.sin_family = AF_INET;
    server_address.sin_addr.s_addr = inet_addr(host);
    server_address.sin_port = htons(port);

    if (bind(server_socket, (struct sockaddr*)&server_address, sizeof(server_address)) == -1) {
        std::cerr << "Failed to bind socket" << std::endl;
        return -1;
    }

    // 监听客户端连接
    if (listen(server_socket, 5) == -1) {
        std::cerr << "Failed to listen on socket" << std::endl;
        return -1;
    }

    std::cout << "Server listening on " << host << ":" << port << std::endl;

    while (true) {
        // 接受客户端连接请求
        struct sockaddr_in client_address{};
        socklen_t addr_len = sizeof(client_address);
        int client_socket = accept(server_socket, (struct sockaddr*)&client_address, &addr_len);
        if (client_socket == -1) {
            std::cerr << "Failed to accept client connection" << std::endl;
            continue;
        }

        std::cout << "Accepted connection from " << inet_ntoa(client_address.sin_addr) << ":" << ntohs(client_address.sin_port) << std::endl;

        // 创建子进程处理客户端连接
        pid_t pid = fork();

        if (pid == 0) {
            // 子进程
            close(server_socket); // 关闭服务端Socket
            handle_client(client_socket); // 处理客户端连接
            break;
        } else if (pid < 0) {
            // 创建进程失败
            std::cerr << "Failed to create child process" << std::endl;
            close(client_socket);
            continue;
        }

        // 父进程，关闭客户端Socket
        close(client_socket);
    }

    // 关闭服务端Socket
    close(server_socket);

    return 0;
}
```

**客户端程序（client.cpp）：**

```cpp
#include <iostream>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>
#include <unistd.h>
#include <cstring>

int main() {
    // 定义服务器 IP 和端口
    char* server_ip = "127.0.0.1";
    int port = 12345;

    // 创建 TCP Socket
    int client_socket = socket(AF_INET, SOCK_STREAM, 0);
    if (client_socket == -1) {
        std::cerr << "Failed to create socket" << std::endl;
        return -1;
    }

    // 连接服务器
    struct sockaddr_in server_address{};
    server_address.sin_family = AF_INET;
    server_address.sin_addr.s_addr = inet_addr(server_ip);
    server_address.sin_port = htons(port);

    if (connect(client_socket, (struct sockaddr*)&server_address, sizeof(server_address)) == -1) {
        std::cerr << "Failed to connect to server" << std::endl;
        return -1;
    }

    std::cout << "Connected to " << server_ip << ":" << port << std::endl;

    // 发送数据到服务器
    char message[] = "Hello, server!";
    ssize_t sent_bytes = send(client_socket, message, strlen(message), 0);
    if (sent_bytes == -1) {
        std::cerr << "Failed to send data to server" << std::endl;
        return -1;
    }

    // 接收服务器响应
    char buffer[1024];
    memset(buffer, 0, sizeof(buffer));
    ssize_t recv_bytes = recv(client_socket, buffer, sizeof(buffer), 0);
    if (recv_bytes == -1) {
        std::cerr << "Failed to receive data from server" << std::endl;
        return -1;
    }

    std::cout << "Server response: " << buffer << std::endl;

    // 关闭客户端连接
    close(client_socket);

    return 0;
}
```

请注意，以上代码仅提供了一个基本的框架，实际应用中可能需要添加更多的错误处理和具体业务逻辑。此外，多进程的实现可以使用`fork`或`exec`等系统调用，或者使用C++库提供的进程管理类（如`std::process`）实现。
